{
  "claim": "a spec-faithful simulated agent follows a spec-valid but false surface; the verifier catches the surface/SOR mismatch",
  "actorLabel": "spec-faithful demonstration actor — simulated",
  "simulated": true,
  "specVersion": "taxonomy-v1+acp-extract-2026-07-02+ucp-pin-2026-04-08",
  "selection": {
    "intent": "Order the \"Smoked Brisket Plate\" if the published feed lists it as available.",
    "targetTitle": "Smoked Brisket Plate",
    "selectedItemId": "item-006-v1",
    "selectedTitle": "Smoked Brisket Plate",
    "observedPrice": "12.00",
    "observedCurrency": "USD",
    "observedAvailability": "in_stock"
  },
  "totalFindingCount": 16,
  "beats": [
    {
      "id": "actor-reads",
      "title": "The agent reads the published feed — spec-faithful demonstration actor — simulated",
      "plain": "A shopping agent reads the published menu feed — the same data any AI assistant would consume — and never sees the restaurant's own records.",
      "lines": [
        "intent: Order the \"Smoked Brisket Plate\" if the published feed lists it as available.",
        "source read: the published ACP feed only (no system-of-record access)"
      ]
    },
    {
      "id": "actor-selects",
      "title": "The agent selects an item, trusting the surface",
      "plain": "Trusting the feed at face value, the agent picks its target item and is ready to order it at the price the surface shows.",
      "lines": [
        "selected item: \"Smoked Brisket Plate\" (row id item-006-v1)",
        "read off the surface: price 12.00 USD · availability in_stock",
        "the agent is now ready to order at that price — the demo stops here (no checkout)."
      ],
      "verdicts": [
        {
          "ok": true,
          "label": "SELECTED (from the surface)"
        }
      ]
    },
    {
      "id": "verifier-finds",
      "title": "The verifier checks that same copy against the records",
      "plain": "The verifier checks the exact same feed against the restaurant's system-of-record and flags what the agent had no way to see.",
      "lines": [
        "1 finding for the selected item (\"Smoked Brisket Plate\"); full report: 16 findings across the whole copy."
      ],
      "findings": [
        {
          "plainLine": "The served price 12.00 does not match the catalog price 10.00.",
          "claimId": "item-006-v1#price.amount",
          "claimSource": "acp-feed",
          "claimField": "price.amount",
          "claimValue": "12.00",
          "referenceRowId": "item-006-v1",
          "ruleId": "LST-PRICE-VALUE",
          "severity": "error",
          "category": "price"
        }
      ],
      "verdicts": [
        {
          "ok": false,
          "label": "DRIFT ON THE SELECTED ITEM — the agent could not have seen it"
        }
      ]
    },
    {
      "id": "conformance-foil",
      "title": "Conformance-foil: spec-valid is not the same as true",
      "plain": "The same document passes the official schema check — it is correctly shaped — and still misstates the price versus the records.",
      "lines": [
        "passes the official schema check; still lies — conformance: PASS (spec-shape); truth: 1 finding(s) vs the system-of-record."
      ],
      "findings": [
        {
          "plainLine": "The served price 23.50 does not match the catalog price 21.50.",
          "claimId": "item-001-v1#price.amount",
          "claimSource": "ucp-catalog",
          "claimField": "price.amount",
          "claimValue": "23.50",
          "referenceRowId": "item-001-v1",
          "ruleId": "LST-PRICE-VALUE",
          "severity": "error",
          "category": "price"
        }
      ],
      "verdicts": [
        {
          "ok": true,
          "label": "CONFORMANT (spec-valid)"
        },
        {
          "ok": false,
          "label": "FALSE vs SOR (still lies)"
        }
      ]
    }
  ]
}
